def find_pairs_with_sum(arr, target_sum):
    arr.sort()

    left = 0
    right = len(arr) - 1
    pairs = []

    while left < right:
        current_sum = arr[left] + arr[right]

        if current_sum == target_sum:
            pairs.append((arr[left], arr[right]))
            left += 1
            right -= 1
        elif current_sum < target_sum:
            left += 1
        else:
            right -= 1

    return pairs
